const fs = require('fs');
const path = require('path');

const FILE = path.join(__dirname, 'lessons.json');

// Helper factories
const M = (id, title, difficulty, duration, objectives, content, exercises, quiz, videos) => ({ id, title, difficulty, duration, objectives, content, exercises, quiz, videos });
const P = (value) => ({ type: 'paragraph', value });
const A = (value) => ({ type: 'analogy', value });
const C = (title, language, code, explanation) => ({ type: 'code', title, language, code, explanation: explanation.map(([c, d]) => ({ code: c, desc: d })) });
const E = (e) => e;
const Q = (question, options, answer) => ({ question, options, answer });
const V = (title, creator, url) => ({ title, creator, url });

